mapper.select:
select 
from reference_repository_states

    where repository_id > #{afterRepositoryId}

order by repository_id
limit #{limit}

mapper.insert:
insert into reference_repository_states(
    repository_id, branch, target_commit_hash, generation, status, credential_user_id,
    trace_id, last_error, initialized_at, created_at, updated_at
) values (
    #{row.repositoryId}, #{row.branch}, #{row.targetCommitHash}, #{row.generation}, #{row.status},
    #{row.credentialUserId}, #{row.traceId}, #{row.lastError}, #{row.initializedAt},
    #{row.createdAt}, #{row.updatedAt}
)
on conflict (repository_id) do nothing

mapper.update:
update reference_repository_states
set target_commit_hash = #{row.targetCommitHash},
    generation = #{row.generation},
    status = #{row.status},
    credential_user_id = #{row.credentialUserId},
    trace_id = #{row.traceId},
    last_error = #{row.lastError},
    updated_at = #{row.updatedAt}
where repository_id = #{row.repositoryId}
  and branch = #{row.branch}
  and generation = #{expectedGeneration}
  and status in ('READY', 'FAILED')

update reference_repository_replicas
set status = 'DEFERRED', lease_token = null, lease_until = null, updated_at = #{now}
where repository_id = #{repositoryId}
  and generation = #{generation}
  and status in ('PENDING', 'RETRY_WAIT', 'PROCESSING')
  and exists (
      select 1 from reference_repository_states state
      where state.repository_id = #{repositoryId} and state.generation = #{generation}
  )

  and linux_server_id not in

      #{serverId}

update reference_repository_replicas
set status = 'PROCESSING', lease_token = #{leaseToken}, lease_until = #{leaseUntil}, updated_at = #{now}
where repository_id = #{repositoryId}
  and linux_server_id = #{linuxServerId}
  and generation = #{generation}
  and (
    status in ('PENDING', 'DEFERRED')
    or (status = 'RETRY_WAIT' and (next_retry_at is null or next_retry_at <= #{now}))
    or (status = 'PROCESSING' and lease_until <= #{now})
  )

update reference_repository_replicas
set lease_until = #{leaseUntil}, updated_at = #{now}
where repository_id = #{repositoryId}
  and linux_server_id = #{linuxServerId}
  and generation = #{generation}
  and status = 'PROCESSING'
  and lease_token = #{leaseToken}
  and lease_until > #{now}

mapper.select:
select 
from reference_repository_replicas
where linux_server_id = #{linuxServerId}
  and (
    status in ('PENDING', 'DEFERRED')
    or (status = 'RETRY_WAIT' and (next_retry_at is null or next_retry_at <= #{now}))
    or (status = 'PROCESSING' and lease_until <= #{now})
  )
order by updated_at, repository_id
limit #{limit}

mapper.update:
update reference_repository_replicas
set status = 'READY', branch = #{branch}, current_commit_hash = #{commitHash},
    retry_count = 0, next_retry_at = null, lease_token = null, lease_until = null,
    last_error = null, synced_at = #{syncedAt}, updated_at = #{now}
where repository_id = #{repositoryId} and linux_server_id = #{linuxServerId}
  and generation = #{generation} and status = 'PROCESSING'
  and lease_token = #{leaseToken} and lease_until > #{now}

update reference_repository_replicas
set status = 'RETRY_WAIT', retry_count = #{retryCount}, next_retry_at = #{nextRetryAt},
    lease_token = null, lease_until = null, last_error = #{lastError}, updated_at = #{now}
where repository_id = #{repositoryId} and linux_server_id = #{linuxServerId}
  and generation = #{generation} and status = 'PROCESSING'
  and lease_token = #{leaseToken} and lease_until > #{now}

update reference_repository_replicas
set status = 'BLOCKED', lease_token = null, lease_until = null,
    last_error = #{lastError}, updated_at = #{now}
where repository_id = #{repositoryId} and linux_server_id = #{linuxServerId}
  and generation = #{generation} and status = 'PROCESSING'
  and lease_token = #{leaseToken} and lease_until > #{now}

update reference_repository_states
set status = #{status}, last_error = #{lastError}, updated_at = #{now}
where repository_id = #{repositoryId} and generation = #{generation}
